// Bookmark Manager API — entrypoint
// See PRODUCT_SPEC.md for full requirements
// The agent will build this out across tasks T1-T6

import express from "express";
import Database from "better-sqlite3";

const app = express();
const PORT = 3000;
const db: Database.Database = new Database("data.db");

app.use(express.json());

db.pragma("foreign_keys = ON");

db.exec(`
  CREATE TABLE IF NOT EXISTS folders (
    id INTEGER PRIMARY KEY,
    name TEXT NOT NULL,
    created_at TEXT NOT NULL,
    updated_at TEXT NOT NULL
  );

  CREATE TABLE IF NOT EXISTS bookmarks (
    id INTEGER PRIMARY KEY,
    url TEXT NOT NULL,
    title TEXT NOT NULL,
    description TEXT,
    folder_id INTEGER,
    created_at TEXT NOT NULL,
    updated_at TEXT NOT NULL,
    FOREIGN KEY (folder_id) REFERENCES folders(id) ON DELETE SET NULL
  )
`);

const bookmarkColumns = db.prepare("PRAGMA table_info(bookmarks)").all() as Array<{ name: string }>;
if (!bookmarkColumns.some((column) => column.name === "folder_id")) {
  db.exec("ALTER TABLE bookmarks ADD COLUMN folder_id INTEGER REFERENCES folders(id) ON DELETE SET NULL");
}

type Bookmark = {
  id: number;
  url: string;
  title: string;
  description: string | null;
  folder_id: number | null;
  created_at: string;
  updated_at: string;
};

type Folder = {
  id: number;
  name: string;
  created_at: string;
  updated_at: string;
};

function isNonEmptyString(value: unknown): value is string {
  return typeof value === "string" && value.trim().length > 0;
}

function isValidUrl(value: string): boolean {
  try {
    new URL(value);
    return true;
  } catch {
    return false;
  }
}

function getBookmark(id: number): Bookmark | undefined {
  return db
    .prepare("SELECT id, url, title, description, folder_id, created_at, updated_at FROM bookmarks WHERE id = ?")
    .get(id) as Bookmark | undefined;
}

function getFolder(id: number): Folder | undefined {
  return db
    .prepare("SELECT id, name, created_at, updated_at FROM folders WHERE id = ?")
    .get(id) as Folder | undefined;
}

function parseFolderId(value: unknown): number | null | undefined {
  if (value === undefined) {
    return undefined;
  }

  if (value === null) {
    return null;
  }

  if (typeof value === "number" && Number.isInteger(value) && value > 0) {
    return value;
  }

  return undefined;
}

function folderExists(id: number): boolean {
  return getFolder(id) !== undefined;
}

function getBookmarksForFolder(folderId: number): Bookmark[] {
  return db
    .prepare(
      "SELECT id, url, title, description, folder_id, created_at, updated_at FROM bookmarks WHERE folder_id = ? ORDER BY id ASC",
    )
    .all(folderId) as Bookmark[];
}

app.get("/health", (_req, res) => {
  res.status(200).json({ status: "ok" });
});

app.post("/bookmarks", (req, res) => {
  const { url, title, description, folder_id } = req.body as {
    url?: unknown;
    title?: unknown;
    description?: unknown;
    folder_id?: unknown;
  };

  if (!isNonEmptyString(url)) {
    return res.status(400).json({ error: "url is required" });
  }

  if (!isValidUrl(url)) {
    return res.status(400).json({ error: "url must be a valid URL" });
  }

  if (!isNonEmptyString(title)) {
    return res.status(400).json({ error: "title is required" });
  }

  const parsedFolderId = parseFolderId(folder_id);
  if (folder_id !== undefined && parsedFolderId === undefined) {
    return res.status(400).json({ error: "folder_id must be an existing folder id or null" });
  }

  if (typeof parsedFolderId === "number" && !folderExists(parsedFolderId)) {
    return res.status(400).json({ error: "folder_id does not reference an existing folder" });
  }

  const now = new Date().toISOString();
  const result = db
    .prepare(
      `
        INSERT INTO bookmarks (url, title, description, folder_id, created_at, updated_at)
        VALUES (?, ?, ?, ?, ?, ?)
      `,
    )
    .run(
      url.trim(),
      title.trim(),
      typeof description === "string" && description.length > 0 ? description : null,
      parsedFolderId ?? null,
      now,
      now,
    );

  const bookmark = getBookmark(Number(result.lastInsertRowid));
  return res.status(201).json(bookmark);
});

app.get("/bookmarks", (_req, res) => {
  const bookmarks = db
    .prepare("SELECT id, url, title, description, folder_id, created_at, updated_at FROM bookmarks ORDER BY id ASC")
    .all() as Bookmark[];

  res.status(200).json(bookmarks);
});

app.get("/bookmarks/:id", (req, res) => {
  const id = Number(req.params.id);
  const bookmark = Number.isInteger(id) ? getBookmark(id) : undefined;

  if (!bookmark) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  return res.status(200).json(bookmark);
});

app.put("/bookmarks/:id", (req, res) => {
  const id = Number(req.params.id);
  const existing = Number.isInteger(id) ? getBookmark(id) : undefined;

  if (!existing) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  const { url, title, description, folder_id } = req.body as {
    url?: unknown;
    title?: unknown;
    description?: unknown;
    folder_id?: unknown;
  };

  if (url !== undefined && !isNonEmptyString(url)) {
    return res.status(400).json({ error: "url must be a non-empty string" });
  }

  if (typeof url === "string" && !isValidUrl(url)) {
    return res.status(400).json({ error: "url must be a valid URL" });
  }

  if (title !== undefined && !isNonEmptyString(title)) {
    return res.status(400).json({ error: "title must be a non-empty string" });
  }

  const parsedFolderId = parseFolderId(folder_id);
  if (folder_id !== undefined && parsedFolderId === undefined) {
    return res.status(400).json({ error: "folder_id must be an existing folder id or null" });
  }

  if (typeof parsedFolderId === "number" && !folderExists(parsedFolderId)) {
    return res.status(400).json({ error: "folder_id does not reference an existing folder" });
  }

  const nextUrl = typeof url === "string" ? url.trim() : existing.url;
  const nextTitle = typeof title === "string" ? title.trim() : existing.title;
  const nextDescription =
    description === undefined
      ? existing.description
      : typeof description === "string" && description.length > 0
        ? description
        : null;
  const nextFolderId = folder_id === undefined ? existing.folder_id : parsedFolderId;
  const updatedAt = new Date().toISOString();

  db.prepare(
    `
      UPDATE bookmarks
      SET url = ?, title = ?, description = ?, folder_id = ?, updated_at = ?
      WHERE id = ?
    `,
  ).run(nextUrl, nextTitle, nextDescription, nextFolderId, updatedAt, id);

  return res.status(200).json(getBookmark(id));
});

app.delete("/bookmarks/:id", (req, res) => {
  const id = Number(req.params.id);
  const result = Number.isInteger(id)
    ? db.prepare("DELETE FROM bookmarks WHERE id = ?").run(id)
    : { changes: 0 };

  if (result.changes === 0) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  return res.status(204).send();
});

app.post("/folders", (req, res) => {
  const { name } = req.body as { name?: unknown };

  if (!isNonEmptyString(name)) {
    return res.status(400).json({ error: "name is required" });
  }

  const now = new Date().toISOString();
  const result = db
    .prepare(
      `
        INSERT INTO folders (name, created_at, updated_at)
        VALUES (?, ?, ?)
      `,
    )
    .run(name.trim(), now, now);

  return res.status(201).json(getFolder(Number(result.lastInsertRowid)));
});

app.get("/folders", (_req, res) => {
  const folders = db.prepare("SELECT id, name, created_at, updated_at FROM folders ORDER BY id ASC").all() as Folder[];

  return res.status(200).json(folders);
});

app.get("/folders/:id", (req, res) => {
  const id = Number(req.params.id);
  const folder = Number.isInteger(id) ? getFolder(id) : undefined;

  if (!folder) {
    return res.status(404).json({ error: "folder not found" });
  }

  return res.status(200).json({ ...folder, bookmarks: getBookmarksForFolder(id) });
});

app.put("/folders/:id", (req, res) => {
  const id = Number(req.params.id);
  const existing = Number.isInteger(id) ? getFolder(id) : undefined;

  if (!existing) {
    return res.status(404).json({ error: "folder not found" });
  }

  const { name } = req.body as { name?: unknown };

  if (name !== undefined && !isNonEmptyString(name)) {
    return res.status(400).json({ error: "name must be a non-empty string" });
  }

  const updatedAt = new Date().toISOString();
  db.prepare("UPDATE folders SET name = ?, updated_at = ? WHERE id = ?").run(
    typeof name === "string" ? name.trim() : existing.name,
    updatedAt,
    id,
  );

  return res.status(200).json(getFolder(id));
});

app.delete("/folders/:id", (req, res) => {
  const id = Number(req.params.id);
  const existing = Number.isInteger(id) ? getFolder(id) : undefined;

  if (!existing) {
    return res.status(404).json({ error: "folder not found" });
  }

  const transaction = db.transaction((folderId: number) => {
    db.prepare("UPDATE bookmarks SET folder_id = NULL, updated_at = ? WHERE folder_id = ?").run(
      new Date().toISOString(),
      folderId,
    );
    db.prepare("DELETE FROM folders WHERE id = ?").run(folderId);
  });
  transaction(id);

  return res.status(204).send();
});

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

export default app;
export { db };

